// Compute yesterday in Asia/Taipei robustly (Intl handles tz, no UTC slice trap).
const now = new Date();
const taipei = new Intl.DateTimeFormat('en-CA', { timeZone: 'Asia/Taipei', year: 'numeric', month: '2-digit', day: '2-digit' });
const todayParts = taipei.formatToParts(now).reduce((acc,p) => { if (p.type !== 'literal') acc[p.type] = p.value; return acc; }, {});
const todayTaipei = `${todayParts.year}-${todayParts.month}-${todayParts.day}`;
// One day back in Taipei = subtract 24h from the Taipei-formatted today.
const y = new Date(todayTaipei + 'T00:00:00+08:00');
y.setUTCDate(y.getUTCDate() - 1);
const yParts = taipei.formatToParts(y).reduce((acc,p) => { if (p.type !== 'literal') acc[p.type] = p.value; return acc; }, {});
const yesterday = `${yParts.year}-${yParts.month}-${yParts.day}`;
return [{ json: { correlationId: `recon-${yesterday}-${Math.floor(Math.random()*1e6)}`, yesterday, todayTaipei } }];

const yesterday = $node['Stamp yesterday (Taipei)'].json.yesterday;
const correlationId = $node['Stamp yesterday (Taipei)'].json.correlationId;
const rows = $items().map(i => i.json);
const candidates = rows.filter(r => r.op === 'issue' && (r.appliedAt || '').startsWith(yesterday) && r.status === 'issued');
if (candidates.length === 0) return [{ json: { correlationId, yesterday, empty: true, total: 0, green: 0, mismatchRows: [] } }];
return candidates.map(json => ({ json: { ...json, correlationId, yesterday } }));

// Collapse all queries into one summary item.
const items = $items().map(i => i.json);
const correlationId = $node['Stamp yesterday (Taipei)'].json.correlationId;
const yesterday = $node['Stamp yesterday (Taipei)'].json.yesterday;
const mismatchRows = [];
let green = 0;
for (const it of items) {
  const statusCode = Number(it.statusCode ?? 0);
  const body = it.body ?? it;
  const expected = 'ISSUED';
  const actual = body?.result?.status ?? (statusCode >= 200 && statusCode < 300 ? 'UNKNOWN' : 'NETWORK_OR_ERROR');
  if (statusCode >= 200 && statusCode < 300 && actual === expected) green++;
  else mismatchRows.push({ orderId: it.orderId, provider: it.provider, invoiceNumber: body?.result?.invoiceNumber ?? null, expected, actual });
}
return [{ json: { correlationId, yesterday, total: items.length, green, mismatch: mismatchRows.length, mismatchRows } }];

// Fan out mismatches into one item each for Sheet append.
const d = $json;
return (d.mismatchRows || []).map(m => ({ json: { correlationId: d.correlationId, yesterday: d.yesterday, ...m, detectedAt: new Date().toISOString() } }));

